import type { Concept, ConceptGraph } from "../types";

const CONCEPTS: Concept[] = [
  { id: "deployment-path-selectio", term: "deployment path selection", layer: "setup-onboarding", primitive: true, introducedIn: "stage-0", short: "Choosing the account/provider route (direct subscription vs cloud provider) that determines billing, auth, and which features you get before any install happens.", example: "Picking Claude for Teams/Enterprise over Bedrock because the org wants one subscription with centralized billing and Claude-on-web, rather than request-level routing by data sensitivity.", prerequisites: [], contrasts: [] },
  { id: "auth-precedence", term: "authentication precedence", layer: "setup-onboarding", primitive: true, introducedIn: "stage-0", short: "Claude Code resolves credentials through a fixed priority order, so the highest-set mechanism wins regardless of what else is configured.", example: "Setting CLAUDE_CODE_USE_BEDROCK=1 makes cloud-provider creds win over any ANTHROPIC_API_KEY, while a plain Pro user falls through to subscription OAuth from /login.", prerequisites: [], contrasts: [] },
  { id: "headless-token-auth", term: "non-interactive authentication", layer: "setup-onboarding", introducedIn: "stage-0", short: "Long-lived or vault-backed credentials let Claude Code run in CI and scripts where interactive browser login is impossible.", example: "Running claude setup-token to mint a one-year CLAUDE_CODE_OAUTH_TOKEN for a CI job, or using apiKeyHelper to fetch rotating keys from a vault.", prerequisites: ["auth-precedence", "deployment-path-selectio"], contrasts: [] },
  { id: "version-control-fleet", term: "fleet version control", layer: "setup-onboarding", introducedIn: "stage-0", short: "Keeping every team member on a consistent, non-stale Claude Code version, since some install methods auto-update and others silently don't.", example: "Pinning the fleet with managed autoUpdatesChannel=\"stable\" plus minimumVersion so a developer who installed via Homebrew can't silently run a months-old build.", prerequisites: ["deployment-path-selectio"], contrasts: [] },
  { id: "managed-settings-precede", term: "managed settings precedence", layer: "setup-onboarding", introducedIn: "stage-0", short: "Org-controlled policy that overrides all local user and project config, delivered through ranked sources so admins can enforce rules developers can't undo.", example: "A security team deploys permissions.deny entries via the admin console so that, even though array settings merge, a developer can extend but never remove the managed deny.", prerequisites: ["auth-precedence"], contrasts: [] },
  { id: "permissions-plus-sandbox", term: "permissions paired with sandboxing", layer: "setup-onboarding", introducedIn: "stage-0", short: "Tool-level allow/deny rules only constrain known tools, so true isolation requires combining them with OS-level filesystem and network sandboxing.", example: "Denying WebFetch doesn't stop network access because allowed Bash can run curl, so the lead also sets sandbox.network.allowedDomains to close the gap at the OS layer.", prerequisites: ["deployment-path-selectio"], contrasts: [] },
  { id: "per-repo-context-artifac", term: "per-repo onboarding artifacts", layer: "setup-onboarding", introducedIn: "stage-0", short: "Checked-in files at the repo root that give every team member identical project context and tooling regardless of which editor surface they use.", example: "Running /init to write a CLAUDE.md of build commands and conventions, plus a committed .mcp.json so everyone inherits the same Jira and GitHub MCP servers.", prerequisites: ["version-control-fleet"], contrasts: [] },
  { id: "reusable-workflows-skill", term: "skills and hooks", layer: "setup-onboarding", introducedIn: "stage-0", short: "Shareable units that capture team procedures (skills, model-invoked) and enforce deterministic policy on events (hooks), distributed by checking files into the repo.", example: "Saving a /review-pr skill as .claude/skills/review-pr/SKILL.md so colleagues adopt it by copying the file, and a Stop hook that fires a lint before every commit.", prerequisites: ["per-repo-context-artifac"], contrasts: [] },
  { id: "claude-md-memory-files", term: "CLAUDE.md memory files", layer: "config-memory", primitive: true, introducedIn: "stage-1", short: "Markdown instruction files loaded into every session's context to give Claude persistent guidance, discovered by walking up the directory tree with more-specific files winning on conflict.", example: "Committing a project-root CLAUDE.md that lists the team's build/test commands and 'API handlers live in src/api/handlers/', loaded alongside each teammate's personal ~/.claude/CLAUDE.md.", prerequisites: [], contrasts: [] },
  { id: "guidance-vs-enforcement", term: "guidance vs enforcement", layer: "config-memory", introducedIn: "stage-1", short: "CLAUDE.md and rules are non-binding advice injected as context with no compliance guarantee, so anything that must never happen requires permissions, hooks, or managed settings instead.", example: "Using CLAUDE.md to say 'we run npm test before committing' (a norm) but a PreToolUse hook or deny rule to actually block secret-file reads, since 'don't read .env' in CLAUDE.md is not enforcement.", prerequisites: ["claude-md-memory-files"], contrasts: [] },
  { id: "settings-precedence-and-", term: "settings precedence and merging", layer: "config-memory", introducedIn: "stage-1", short: "Config layers (user < project < local < CLI/env < managed) combine by merging arrays across all scopes while scalars take the most-specific value, with managed settings always winning.", example: "A team's .claude/settings.json model and a developer's settings.local.json model both apply, but the most-local model value wins, while permission allow-lists from every layer are unioned together.", prerequisites: ["managed-settings-precede"], contrasts: [] },
  { id: "scoped-config-and-commit", term: "committed vs personal config scope", layer: "config-memory", introducedIn: "stage-1", short: "Each config artifact has a deliberate home — source-controlled for shared team config, gitignored or user-level for personal/secret state that must never be committed.", example: "Committing .claude/settings.json and .mcp.json for the team while keeping settings.local.json, CLAUDE.local.md, and ~/.claude.json (OAuth/auth state) out of version control.", prerequisites: ["settings-precedence-and-", "per-repo-context-artifac"], contrasts: [] },
  { id: "permission-rules", term: "permission rules", layer: "config-memory", introducedIn: "stage-1", short: "Tool(pattern) allow/deny/ask entries that merge across scopes where deny always beats allow, matching commands literally rather than by semantics or executable.", example: "Adding Bash(npm run test *) to permissions.allow and Read(./.env.*) to deny, knowing Bash(rm *) won't actually block /bin/rm so a hook or sandbox is needed for a real guarantee.", prerequisites: ["permissions-plus-sandbox", "settings-precedence-and-"], contrasts: [] },
  { id: "claude-md-authoring-disc", term: "CLAUDE.md authoring discipline", layer: "config-memory", introducedIn: "stage-1", short: "Keep instruction files short (~200 lines), concrete, and verifiable because length and vagueness reduce adherence even though the file always loads in full.", example: "Splitting a bloated team CLAUDE.md into .claude/rules/*.md and moving task-specific guidance into path-scoped rules so it only loads when Claude reads a matching file.", prerequisites: ["claude-md-memory-files"], contrasts: [] },
  { id: "imports-and-path-scoped-", term: "imports and path-scoped rules", layer: "config-memory", introducedIn: "stage-1", short: "@path imports inline another file's full contents at launch (no context savings), while rules with paths: frontmatter defer loading until Claude touches a matching file.", example: "Putting @AGENTS.md at the top of CLAUDE.md to reuse existing instructions, versus a .claude/rules/frontend.md with paths: 'src/**/*.tsx' that loads only when a React file is read.", prerequisites: ["claude-md-authoring-disc"], contrasts: [] },
  { id: "auto-memory-vs-claude-md", term: "auto memory vs CLAUDE.md", layer: "config-memory", introducedIn: "stage-1", short: "Auto memory (MEMORY.md) is machine-local and written by Claude itself for quick-add facts, distinct from the human-authored, source-controlled CLAUDE.md.", example: "Saying 'always use pnpm' or using #-prefixed quick-add writes to per-project auto memory under ~/.claude/projects/, not to the committed CLAUDE.md the team reviews.", prerequisites: ["claude-md-memory-files"], contrasts: [] },
  { id: "team-mcp-server-config", term: "team MCP server configuration", layer: "config-memory", introducedIn: "stage-1", short: "Approved MCP servers are declared in a repo-root .mcp.json using absolute paths and ${ENV_VAR} secret references, requiring a one-time per-developer approval before they load.", example: "Committing .mcp.json at the repo root with a github server using ${GITHUB_TOKEN} in its env block, which each teammate approves once via /mcp on first clone.", prerequisites: ["scoped-config-and-commit"], contrasts: [] },
  { id: "settings-scope-precedenc", term: "settings scope precedence", layer: "permissions-security-gov", introducedIn: "stage-2", short: "The ranked layering of config sources (managed > CLI args > local project > shared project > user) that decides which value wins.", example: "A team checks .claude/settings.json into version control for shared allow/deny lists while each dev keeps personal overrides in gitignored .claude/settings.local.json.", prerequisites: ["settings-precedence-and-"], contrasts: [] },
  { id: "deny-ask-allow-evaluatio", term: "deny/ask/allow rule evaluation", layer: "permissions-security-gov", introducedIn: "stage-2", short: "Permission rules are evaluated in the fixed order deny then ask then allow, with first match winning regardless of how specific a rule is.", example: "A broad Bash deny rule blocks a command even when a narrower Bash(npm test) allow rule also matches it.", prerequisites: ["permission-rules"], contrasts: [] },
  { id: "enforcement-vs-guidance", term: "enforcement vs guidance", layer: "permissions-security-gov", introducedIn: "stage-2", short: "CLAUDE.md and prompts only shape what Claude tries to do; only permission rules, modes, hooks, and sandboxes actually grant or revoke access.", example: "Writing 'never force push' in CLAUDE.md does not guarantee it; you must add a permissions.deny rule for a hard guarantee that survives context compaction.", prerequisites: ["guidance-vs-enforcement"], contrasts: [] },
  { id: "permission-modes", term: "permission modes", layer: "permissions-security-gov", introducedIn: "stage-2", short: "Named operating profiles (default, acceptEdits, plan, auto, dontAsk, bypassPermissions) that set the baseline prompting behavior for tool calls.", example: "A CI pipeline uses dontAsk mode so anything that would prompt is auto-denied non-interactively, while a developer uses acceptEdits to auto-apply edits within the working directory.", prerequisites: ["permission-rules", "enforcement-vs-guidance"], contrasts: [] },
  { id: "protected-paths", term: "protected paths", layer: "permissions-security-gov", introducedIn: "stage-2", short: "A built-in set of sensitive dirs and files (like .git, .claude, shell rc files, .mcp.json) whose writes are never auto-approved in any mode except bypass, even by allow rules.", example: "Even with a broad allow rule and acceptEdits mode, Claude still prompts before editing a developer's .bashrc or the project's .git directory.", prerequisites: ["permission-modes"], contrasts: [] },
  { id: "permission-rule-syntax", term: "permission rule syntax", layer: "permissions-security-gov", introducedIn: "stage-2", short: "The Tool(specifier) matching language with space-as-word-boundary wildcards, compound-command awareness, and path anchors that determines exactly which tool calls a rule covers.", example: "Bash(devbox run *) accidentally allows arbitrary commands because the devbox wrapper isn't stripped, so the team writes Bash(devbox run npm test) instead.", prerequisites: ["permission-rules"], contrasts: [] },
  { id: "auto-mode-classifier", term: "auto mode classifier", layer: "permissions-security-gov", introducedIn: "stage-2", short: "A per-action LLM safety gate that blocks irreversible or out-of-environment tool calls, but is a second gate rather than a hard isolation boundary, and runs after deny/ask rules.", example: "Auto mode soft-blocks a force-push, but because soft_deny can be overridden by a dev allow, the team uses permissions.deny for absolute bans and lists trusted git orgs in the environment section.", prerequisites: ["permission-modes", "deny-ask-allow-evaluatio"], contrasts: [] },
  { id: "bash-sandbox-isolation", term: "Bash sandbox isolation", layer: "permissions-security-gov", introducedIn: "stage-2", short: "OS-level enforcement (Seatbelt/bubblewrap) confining Bash and child processes to scoped filesystem and network access, the only real isolation boundary versus rule-based checks.", example: "Because the default sandbox still lets Bash read ~/.ssh and ~/.aws/credentials, and fails open if it can't start, the team adds denyRead rules and sets failIfUnavailable: true for a managed gate.", prerequisites: ["permissions-plus-sandbox", "enforcement-vs-guidance"], contrasts: [] },
  { id: "commercial-account-terms", term: "commercial account terms", layer: "permissions-security-gov", introducedIn: "stage-2", short: "Using Team/Enterprise/API plans (not personal Free/Pro/Max) so company code and prompts are never used for training and retention is short.", example: "An org bans personal Pro/Max accounts for company code and standardizes on Team plans, where prompts aren't trained on unless they explicitly opt into the Development Partner Program.", prerequisites: ["deployment-path-selectio"], contrasts: [] },
  { id: "settings-precedence", term: "configuration scope and precedence", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Claude Code settings resolve through ordered layers where later layers override earlier, determining which config actually takes effect.", example: "A team commits hooks to .claude/settings.json, but managed policy settings (highest layer) can impose guardrails users cannot override.", prerequisites: ["settings-scope-precedenc"], contrasts: [] },
  { id: "shared-vs-personal-confi", term: "shared vs. personal config placement", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Team-standard config goes in committable files while personal or experimental config stays in user-level or gitignored files so it doesn't impose on teammates.", example: "Commit team-standard permissions to .claude/settings.json, but keep an experimental hook in gitignored .claude/settings.local.json.", prerequisites: ["settings-precedence", "scoped-config-and-commit"], contrasts: [] },
  { id: "hooks-lifecycle-events", term: "hooks on lifecycle events", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Hooks run deterministic logic at named, case-sensitive lifecycle events, configured as sibling keys under a single hooks object with matchers selecting when they fire.", example: "A PreToolUse hook matching Bash runs a script before every Bash tool call to audit or block the command.", prerequisites: ["enforcement-vs-guidance", "reusable-workflows-skill"], contrasts: [] },
  { id: "hook-exit-code-blocking", term: "hook exit-code blocking semantics", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "A command hook blocks an action only with exit code 2 (stderr fed back to Claude); exit 1 and other nonzero codes are non-blocking, and exit 0 may add context.", example: "A Stop hook that exits 1 when tests fail does NOT block the stop; it must exit 2 to actually halt and report the failure.", prerequisites: ["hooks-lifecycle-events"], contrasts: [] },
  { id: "pretooluse-policy-enforc", term: "PreToolUse policy enforcement", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "PreToolUse hooks fire before any permission-mode check, so a deny decision is the only way to enforce policy users cannot bypass even in skip-permissions mode.", example: "A PreToolUse hook returning permissionDecision deny blocks rm -rf even when the user launched with --dangerously-skip-permissions.", prerequisites: ["hooks-lifecycle-events", "permission-modes"], contrasts: [] },
  { id: "hook-matcher-syntax", term: "hook matcher and if-filter selection", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Matchers select which tool/event a hook fires on using exact, pipe-list, or regex syntax (case-sensitive), and the if filter further narrows by tool arguments but fails open.", example: "A matcher of Edit|Write fires on both edit tools, while if Bash(git *) only spawns the hook for git subcommands.", prerequisites: ["hooks-lifecycle-events"], contrasts: [] },
  { id: "hook-merge-most-restrict", term: "parallel hook merge with most-restrictive-wins", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Multiple matching hooks run in parallel to completion then merge their results, with the most restrictive permission decision winning (deny > defer > ask > allow).", example: "If one PreToolUse hook says allow and another says deny for the same Bash call, the call is denied while both hooks' side effects still run.", prerequisites: ["hook-matcher-syntax", "deny-ask-allow-evaluatio"], contrasts: [] },
  { id: "slash-command-invocation", term: "slash command invocation and availability", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "A slash command is recognized only at the start of a message with trailing text as arguments, and its presence is conditional on platform, plan, and environment.", example: "/code-review high --fix is parsed as a command with arguments, but /upgrade only appears for Pro/Max users.", prerequisites: ["reusable-workflows-skill"], contrasts: [] },
  { id: "frontmatter-scoped-hooks", term: "component-scoped and plugin hooks", layer: "skills-hooks-commands", introducedIn: "stage-3", short: "Hooks can be distributed via plugins or scoped to a skill/agent's lifecycle through frontmatter, active only while that component is active.", example: "A skill declares a hooks: block in its frontmatter with once:true so the hook fires a single time per session while the skill is active, then removes itself.", prerequisites: ["hooks-lifecycle-events"], contrasts: [] },
  { id: "multi-context-approach-s", term: "Choosing a multi-context approach", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Claude Code offers four ways to run work in more than one context, picked by who coordinates the work and whether the workers need to talk to each other.", example: "A side task that would flood the main conversation with logs goes to a subagent; genuinely parallelizable peer work where Claude coordinates equals an agent team; a 500-file migration goes to a dynamic workflow.", prerequisites: ["enforcement-vs-guidance"], contrasts: [] },
  { id: "subagent", term: "Subagent", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "A worker defined in a Markdown file (YAML frontmatter plus body-as-system-prompt) that runs in a fresh isolated context and returns only a summary to the conversation that spawned it.", example: "A reviewer subagent in .claude/agents/ that searches the repo in its own context and reports back findings without dumping every file it read into the main conversation.", prerequisites: ["multi-context-approach-s", "claude-md-memory-files"], contrasts: [] },
  { id: "definition-scope-precede", term: "Definition scope and precedence", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Subagent definitions resolve across ranked scopes (managed, CLI flag, project, user, plugin), and on a name collision the higher-priority or closest-to-cwd definition wins.", example: "Check a project's reviewer subagent into .claude/agents/ so the team shares it; an org-wide standard reviewer deployed via managed settings takes precedence over it.", prerequisites: ["subagent", "settings-scope-precedenc"], contrasts: [] },
  { id: "frontmatter-configuratio", term: "Subagent frontmatter configuration", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Frontmatter fields tune each subagent's routing, tools, model, permissions, memory, and isolation so it does one focused job with the minimum capability needed.", example: "Give a reviewer disallowedTools: Write, Edit and model: haiku so it inherits read tools cheaply but cannot modify files.", prerequisites: ["subagent"], contrasts: [] },
  { id: "tool-and-context-scoping", term: "Tool and context scoping for workers", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Limiting a worker to the minimum tools, inlining its MCP servers, and using hooks for fine-grained gating keeps capability tight and keeps tool descriptions out of the main conversation's context.", example: "A PreToolUse hook (exit code 2 to block) lets a data subagent run read-only SQL while blocking INSERT/UPDATE/DELETE that the tools allowlist cannot distinguish.", prerequisites: ["frontmatter-configuratio", "hook-matcher-syntax"], contrasts: [] },
  { id: "fork-vs-fresh-subagent", term: "Fork vs fresh subagent", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "A fork inherits the entire current conversation (and reuses its prompt cache) for a side task, whereas a normal subagent starts from a fresh isolated context.", example: "Use /fork to try two refactor approaches that both need the full discussion so far, instead of spawning a fresh subagent that would have to be re-briefed from scratch.", prerequisites: ["subagent"], contrasts: [] },
  { id: "agent-team", term: "Agent team", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "An experimental setup where a lead Claude supervises teammates who share a task list and message each other 1:1, used for genuinely parallel work that needs peer coordination.", example: "Enable CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 and have the lead spawn three teammates to review separate layers of a change, messaging each other as they find cross-layer issues.", prerequisites: ["multi-context-approach-s"], contrasts: [] },
  { id: "teammate-context-and-per", term: "Teammate context and permissions", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Teammates load project context but NOT the lead's conversation history, start from the lead's permission settings, and don't inherit the lead's model, so the spawn prompt and pre-approvals must carry all task-specific detail.", example: "Put files, scope, and required output format (such as severity ratings) in the spawn prompt and pre-approve common operations before spawning, since teammate permission requests bubble up to the lead.", prerequisites: ["agent-team", "permission-modes"], contrasts: [] },
  { id: "task-coordination-and-ga", term: "Task coordination and quality gating", layer: "subagents-agent-teams", introducedIn: "stage-4", short: "Teams coordinate through a shared task list with dependencies and file-locked claiming, and enforce quality via plan approval plus block-and-feedback hooks like TaskCompleted.", example: "Tell the lead to require plan approval and only approve plans that include test coverage; a TaskCompleted hook (exit code 2) blocks a teammate from marking a task done prematurely.", prerequisites: ["agent-team", "hooks-lifecycle-events"], contrasts: [] },
  { id: "mcp-server", term: "MCP server", layer: "mcp", introducedIn: "stage-5", short: "An external process that gives Claude Code additional tools via the Model Context Protocol; Anthropic doesn't security-audit them, so approval is the admin's responsibility.", example: "A GitHub MCP server that lets Claude read issues and open PRs, which a team must vet before connecting.", prerequisites: ["team-mcp-server-config"], contrasts: [] },
  { id: "mcp-scope", term: "MCP scope (local / project / user)", layer: "mcp", introducedIn: "stage-5", short: "Where a server's definition is stored, which determines who sees it and which projects it applies to; scope is fixed at add time and changing it requires remove-then-re-add.", example: "Using --scope project to write a server into .mcp.json so the whole team gets it, versus --scope user for a personal docs-search server in every project.", prerequisites: ["mcp-server", "settings-scope-precedenc"], contrasts: [] },
  { id: "config-as-code-distribut", term: "Configuration-as-code distribution", layer: "mcp", introducedIn: "stage-5", short: "Sharing MCP servers with a team by committing the project-scope .mcp.json to version control so every clone gets the same tools (after an approval prompt), with secrets kept out via env-var expansion.", example: "Committing .mcp.json with ${GITHUB_TOKEN} so teammates approve the server on clone but supply their own token from the environment.", prerequisites: ["mcp-scope", "scoped-config-and-commit"], contrasts: [] },
  { id: "scope-precedence", term: "Scope precedence (non-merging)", layer: "mcp", introducedIn: "stage-5", short: "When the same server is defined in multiple places, only the entire entry from the highest-precedence source wins and fields are never merged (local > project > user > plugin > claude.ai connector).", example: "A teammate's local definition of github fully overrides the committed project entry rather than merging in its extra headers.", prerequisites: ["mcp-scope"], contrasts: [] },
  { id: "plugin-bundled-servers", term: "Plugin-bundled MCP servers", layer: "mcp", introducedIn: "stage-5", short: "Packaging servers inside a plugin so they auto-start when the plugin is enabled, giving zero-touch consistency without anyone running manual add commands.", example: "Distributing the team's standard server set through a managed plugin marketplace so enabling the plugin connects every tool automatically.", prerequisites: ["mcp-server"], contrasts: [] },
  { id: "mcp-authentication", term: "MCP authentication", layer: "mcp", introducedIn: "stage-5", short: "How Claude Code proves identity to a server: OAuth 2.0 (triggered on a 401/403), a static bearer-token header, or a headersHelper command that generates auth headers fresh at connect time.", example: "Pinning oauth.scopes in .mcp.json to restrict a server to a security-approved subset, or using headersHelper to mint a short-lived internal SSO token per connection.", prerequisites: ["mcp-server"], contrasts: [] },
  { id: "tool-search-context-budg", term: "Tool Search and context budget", layer: "mcp", introducedIn: "stage-5", short: "A default mechanism that defers loading tool definitions (only names load at session start, discovered on demand) so the constraint on number of servers is the context-window budget rather than a per-server cap.", example: "Adding many team servers with minimal context impact under default deferral, while marking a constantly-needed server alwaysLoad so it loads upfront.", prerequisites: ["mcp-server"], contrasts: [] },
  { id: "managed-mcp-governance", term: "Enterprise managed MCP governance", layer: "mcp", introducedIn: "stage-5", short: "Org-wide control of MCP access through admin-deployed managed settings: a managed-mcp.json for an exclusive fixed server set, plus allow/deny lists that should enforce identity by URL or command, never by user-assigned name.", example: "Deploying managed-mcp.json via MDM so users see only the approved servers, with allowedMcpServers matching on serverUrl so a user can't bypass it by renaming a server github.", prerequisites: ["scope-precedence", "managed-settings-precede", "mcp-authentication"], contrasts: [] },
  { id: "plugin", term: "plugin", layer: "plugins-distribution", introducedIn: "stage-6", short: "A self-contained directory that bundles shareable Claude Code components (skills, agents, hooks, MCP/LSP servers, monitors, bin executables) under one namespace.", example: "A `formatter` plugin shipped to the whole team bundles a formatting skill plus a PostToolUse hook in one directory.", prerequisites: ["reusable-workflows-skill", "plugin-bundled-servers"], contrasts: [] },
  { id: "marketplace", term: "marketplace", layer: "plugins-distribution", introducedIn: "stage-6", short: "A catalog of plugins, defined by a marketplace.json, that you first add (register the catalog) and then install individual plugins from.", example: "An org hosts a private Git marketplace at `your-org/claude-plugins` that the team adds once, then installs the `formatter` plugin from it.", prerequisites: ["plugin"], contrasts: [] },
  { id: "settings-scope", term: "settings scope", layer: "plugins-distribution", introducedIn: "stage-6", short: "The level (user, project, local, or managed) that determines which settings file a plugin's enabled state is written to and therefore who receives it.", example: "Installing at project scope writes `enabledPlugins` into `.claude/settings.json`, so every collaborator who clones the repo gets the plugin.", prerequisites: ["settings-scope-precedenc", "plugin"], contrasts: [] },
  { id: "project-scope-vcs-distri", term: "project-scope distribution via VCS", layer: "plugins-distribution", introducedIn: "stage-6", short: "Sharing plugins with a whole team by committing the marketplace registration and enabled-plugins state into the repo's checked-in project settings.", example: "Committing both `extraKnownMarketplaces` and `enabledPlugins` to `.claude/settings.json` auto-prompts collaborators to install when they trust the repo folder.", prerequisites: ["settings-scope", "marketplace"], contrasts: [] },
  { id: "managed-settings-governa", term: "managed (admin) settings", layer: "plugins-distribution", introducedIn: "stage-6", short: "Admin-installed, read-only settings that enforce plugin and marketplace configuration which users cannot modify or remove.", example: "An admin pushes `extraKnownMarketplaces` with `autoUpdate: true` via managed settings so every employee gets the org marketplace and can't disable it.", prerequisites: ["settings-scope", "managed-settings-precede"], contrasts: [] },
  { id: "plugin-authoring-layout", term: "plugin authoring layout", layer: "plugins-distribution", introducedIn: "stage-6", short: "The required directory structure where only plugin.json lives in `.claude-plugin/` and all component dirs sit at the plugin root, with the manifest name acting as the component namespace.", example: "Converting a standalone `.claude/` config means moving `skills/` and `agents/` to the plugin root and putting only `plugin.json` in `.claude-plugin/`, then deleting the original `.claude/` files.", prerequisites: ["plugin"], contrasts: [] },
  { id: "version-pinning-resoluti", term: "version pinning and resolution", layer: "plugins-distribution", introducedIn: "stage-6", short: "How a plugin's effective version is chosen (plugin.json over marketplace entry over git SHA) and how sources are pinned to a ref or SHA for reproducibility.", example: "Pinning a marketplace add to `https://gitlab.com/company/plugins.git#v1.0.0`, while community plugins are SHA-pinned so installs survive deletion of the named tag.", prerequisites: ["plugin-authoring-layout", "marketplace"], contrasts: [] },
  { id: "always-on-cost-budgeting", term: "always-on token cost budgeting", layer: "plugins-distribution", introducedIn: "stage-6", short: "Treating each enabled plugin's standing context and MCP-server token cost as a budget to manage, shipping costly plugins as opt-in.", example: "Setting `defaultEnabled: false` so a plugin with non-deferred MCP servers (which invalidates the prompt cache) installs disabled until a user opts in.", prerequisites: ["plugin", "tool-search-context-budg"], contrasts: [] },
  { id: "plugin-environment-varia", term: "plugin path environment variables", layer: "plugins-distribution", introducedIn: "stage-6", short: "Substituted path variables that let plugin content reference bundled files and persistent state correctly across updates instead of hardcoding paths.", example: "Referencing a bundled script via `${CLAUDE_PLUGIN_ROOT}` (which changes every update) and installing a venv into `${CLAUDE_PLUGIN_DATA}` so it survives updates.", prerequisites: ["plugin-authoring-layout"], contrasts: [] },
  { id: "headless-print-mode", term: "headless (print) mode", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Running Claude Code non-interactively with `claude -p` so it executes one query via the Agent SDK and exits, forming the basis for all scripting and automation.", example: "A CI job runs `claude -p \"review this diff\" --output-format json` instead of an interactive session, with many flags being print-mode-only and no-ops otherwise.", prerequisites: ["headless-token-auth"], contrasts: [] },
  { id: "ci-auth", term: "CI authentication", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Authenticating unattended runs without interactive sign-in, choosing between subscription billing and Console API-usage billing.", example: "A team mints a long-lived token with `claude setup-token` (subscription billing) or uses `claude auth login --console` for per-API-usage billing, never embedding interactive auth in the pipeline.", prerequisites: ["headless-token-auth", "commercial-account-terms"], contrasts: [] },
  { id: "cost-loop-bounding", term: "cost and loop bounding", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Capping an automated run's agentic turns and dollar spend so a pipeline can't run away.", example: "A scheduled job sets `--max-turns 10 --max-budget-usd 5` so a misbehaving prompt stops rather than burning unbounded credits.", prerequisites: ["headless-print-mode"], contrasts: [] },
  { id: "tool-mcp-scoping", term: "tool and MCP scoping", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Controlling which tools and MCP servers an automated agent can access, distinguishing auto-approval, removal-from-context, and call-level denial.", example: "A pipeline pins a team's MCP set with `--mcp-config team.json --strict-mcp-config` and denies all MCP via `--disallowedTools \"mcp__*\"`, knowing `--allowedTools` only auto-approves rather than restricts.", prerequisites: ["headless-print-mode", "tool-search-context-budg"], contrasts: [] },
  { id: "managed-code-review", term: "managed Code Review service", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "A GitHub App service (Team/Enterprise plans) that posts inline PR review comments on configurable triggers, billed separately via usage credits and unable to approve or block on its own.", example: "An org admin enables it once, sets a repo to `After every push`, and builds their own merge gate by parsing the check run's machine-readable severity line since the check always completes neutral.", prerequisites: ["commercial-account-terms"], contrasts: [] },
  { id: "review-md", term: "REVIEW.md control file", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "A short repo-root file injected verbatim as highest-priority instructions into every managed review, used to tune what counts as a blocking finding.", example: "A team's REVIEW.md redefines a red Important finding narrowly for a prototype repo, caps nits at five, and skips review of generated code and lockfiles.", prerequisites: ["managed-code-review"], contrasts: [] },
  { id: "github-actions-integrati", term: "GitHub Actions integration", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Running Claude Code in GitHub-hosted CI via `anthropics/claude-code-action@v1`, triggered by a phrase or a prompt, with API keys stored as repo secrets.", example: "A repo installs the app with `/install-github-app`, stores `ANTHROPIC_API_KEY` as a secret, and gates the job with `if: contains(github.event.comment.body, '@claude')` so it only runs on mention.", prerequisites: ["headless-print-mode", "ci-auth"], contrasts: [] },
  { id: "system-prompt-layering", term: "system prompt layering vs replacement", layer: "automation-ci-integratio", introducedIn: "stage-7", short: "Choosing whether to append extra instructions (preserving default tool guidance and safety) or fully replace the system prompt (dropping all defaults and owning safety yourself).", example: "A team uses `--append-system-prompt` to add a convention while keeping safety guidance, reserving full `--system-prompt` replacement for non-coding pipeline agents.", prerequisites: ["headless-print-mode"], contrasts: [] },
  { id: "shared-claude-md", term: "Shared CLAUDE.md", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "A committed instruction file that loads into context every request and is shared with the whole team when placed at the repo root.", example: "Putting `./CLAUDE.md` in the repo root and checking it into git so every developer's Claude session inherits the same build commands and code-style rules; `CLAUDE.local.md` stays personal via .gitignore.", prerequisites: ["claude-md-memory-files", "scoped-config-and-commit"], contrasts: [] },
  { id: "context-as-constraint", term: "Context as the fundamental constraint", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Performance degrades and cost rises as the 200K-token window fills, and much of it is consumed before the first prompt by config that always loads.", example: "A 400-line CLAUDE.md plus several connected MCP servers fill a large share of the window at session start, leaving less room and degrading answers on the actual task, so the file must be kept under 200 lines.", prerequisites: ["claude-md-memory-files"], contrasts: [] },
  { id: "feature-precedence", term: "Per-feature precedence and four config levels", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Config exists at user, project, plugin, and managed levels, but each feature type resolves conflicts by its own rule rather than a single uniform hierarchy.", example: "Skills resolve managed > user > project, but CLAUDE.md is additive (all levels contribute) and hooks merge (all matching fire), so an admin's managed policy overrides a developer's skill while every team member's hook still runs.", prerequisites: ["settings-precedence"], contrasts: [] },
  { id: "incremental-setup-by-tri", term: "Build setup incrementally by trigger", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Each kind of recurring friction maps to a specific config artifact, so the team's shared setup grows from observed pain rather than upfront design.", example: "A convention Claude gets wrong twice becomes a CLAUDE.md line; a pasted multi-step playbook on its third use becomes a skill; a repo needing the same setup becomes a packaged plugin.", prerequisites: ["shared-claude-md"], contrasts: [] },
  { id: "hooks-vs-advisory-config", term: "Hooks as enforcement vs advisory instructions", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "CLAUDE.md is a request Claude may ignore, while hooks run deterministically at lifecycle events for anything that must happen every time.", example: "A PreToolUse hook blocks editing `.env` for the whole team, whereas a 'never edit .env' line in the shared CLAUDE.md is only a hope that can be ignored.", prerequisites: ["hooks-lifecycle-events", "shared-claude-md"], contrasts: [] },
  { id: "context-cost-by-feature", term: "Context cost varies by feature", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Different config features charge context differently (full content, descriptions only, deferred schemas, or zero), which determines what to load eagerly versus on demand.", example: "CLAUDE.md costs its full token count every request, skills cost only their description until invoked, and MCP loads tool names upfront but defers full JSON schemas until a tool is actually used.", prerequisites: ["context-as-constraint", "tool-search-context-budg"], contrasts: [] },
  { id: "subagent-context-isolati", term: "Subagent context isolation", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Delegating verbose work to a subagent keeps large file reads and outputs in its own window, returning only a small summary to the main session.", example: "Sending a broad codebase search to a subagent so the file contents stay in its context; the main session only receives a short summary instead of thousands of tokens, but the subagent must be passed needed context explicitly since it doesn't inherit history.", prerequisites: ["context-as-constraint", "subagent"], contrasts: [] },
  { id: "compaction-survival", term: "What survives compaction", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Auto-compaction summarizes history and re-injects only disk-backed config, so durable rules must live in files rather than conversation history.", example: "Root CLAUDE.md and invoked skill bodies are re-injected after compaction, but `paths:`-scoped rules and nested subdirectory CLAUDE.md are lost until a matching file is re-read, so persistent team rules belong in the root CLAUDE.md.", prerequisites: ["context-as-constraint", "shared-claude-md"], contrasts: [] },
  { id: "model-and-effort-cost-le", term: "Model and effort selection as cost lever", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "Choosing the model tier and thinking effort per task is the main spend control, since extended thinking is on by default and bills as output tokens.", example: "Defaulting the team to Sonnet for coding, reserving Opus for complex architecture, using Haiku for simple subagents, and lowering `/effort` so simple tasks don't burn tens of thousands of thinking tokens.", prerequisites: ["context-as-constraint"], contrasts: [] },
  { id: "prompt-caching-prefix", term: "Prompt caching by stable prefix", layer: "optimal-use-context-cost", introducedIn: "stage-8", short: "The API caches by exact-prefix match across stability layers, so keeping early layers unchanged makes most input bill at a fraction of the normal rate.", example: "Keeping the system prompt and project CLAUDE.md stable lets later requests hit the cache at ~10% of input cost; switching model or effort level mid-session is part of the cache key and recomputes the whole prefix.", prerequisites: ["context-as-constraint", "feature-precedence"], contrasts: [] },
  { id: "surface-engine-config-sh", term: "surfaces share one engine and config", layer: "surfaces-mobility", introducedIn: "stage-9", short: "Different ways to run Claude Code (CLI, Desktop, IDE, web) vary in capabilities, but several share the same engine and read the same config files, so one change can affect multiple surfaces at once.", example: "A team edits CLAUDE.md and ~/.claude/settings.json once; because CLI and Desktop run the same engine and share config, the change governs both simultaneously even on the same project.", prerequisites: ["settings-precedence"], contrasts: [] },
  { id: "auth-standardization", term: "auth method determines available features", layer: "surfaces-mobility", introducedIn: "stage-9", short: "How a team authenticates (claude.ai OAuth vs API key vs governed third-party provider) silently enables or disables whole feature sets, so auth is the first team decision to standardize.", example: "An ANTHROPIC_API_KEY left in the environment silently blocks Remote Control, and Bedrock/Vertex/Foundry disable channels, voice, teleport, and Remote Control entirely.", prerequisites: ["auth-precedence", "surface-engine-config-sh"], contrasts: [] },
  { id: "config-mobility", term: "config mobility across surfaces", layer: "surfaces-mobility", introducedIn: "stage-9", short: "Each surface carries a different subset of configuration, so where you put a setting determines whether it reaches a given execution environment.", example: "Claude Code on the web sees only repo-cloned config (CLAUDE.md, .claude/settings.json, .mcp.json) and is blind to local ~/.claude, so standing instructions for cloud sessions must live in the repo.", prerequisites: ["surface-engine-config-sh"], contrasts: [] },
  { id: "managed-settings-gating", term: "managed (admin-governed) settings", layer: "surfaces-mobility", introducedIn: "stage-9", short: "Server-managed settings files override project and user settings and cannot be overridden by users, giving admins a central enforcement layer for org policy.", example: "An admin sets allowedChannelPlugins and disableRemoteControl in a managed settings file so developers cannot re-enable blocked channels or Remote Control.", prerequisites: ["managed-settings-governa"], contrasts: [] },
  { id: "managed-settings-distrib", term: "managed-settings distribution gap", layer: "surfaces-mobility", introducedIn: "stage-9", short: "How a managed policy actually reaches a device differs by surface, so a centrally configured rule does not automatically apply everywhere.", example: "Admin-console pushed managed settings reach CLI and IDE but NOT Desktop, which must instead receive the managed file via MDM (macOS profile or Windows registry).", prerequisites: ["managed-settings-gating", "config-mobility"], contrasts: [] },
  { id: "cloud-environments", term: "cloud session environments", layer: "surfaces-mobility", introducedIn: "stage-9", short: "Web/remote sessions run on isolated managed VMs whose network access and setup script are defined per named environment, controlling what the agent can reach and install.", example: "A team configures a Custom-network environment with a minimal allowlist plus a setup script (appending || true to non-critical steps) so cloud sessions reach internal hosts without full egress.", prerequisites: ["surface-engine-config-sh", "bash-sandbox-isolation"], contrasts: [] },
  { id: "cloud-execution-workflow", term: "remote/cloud execution and teleport", layer: "surfaces-mobility", introducedIn: "stage-9", short: "Cloud sessions are launched, moved, and traced through specific one-directional flows that require pushed branches and share account rate limits.", example: "A developer plans locally with --permission-mode plan, pushes, then runs claude --remote in the cloud, and teleports a CLI session up with claude --teleport (which needs a clean tree and pushed branch).", prerequisites: ["cloud-environments"], contrasts: [] },
  { id: "ide-context-exposure", term: "IDE context exposure and hidden MCP server", layer: "surfaces-mobility", introducedIn: "stage-9", short: "IDE integration auto-sends editor context with each prompt and exposes a hidden built-in MCP server, so allowlists and deny rules must account for what the IDE silently shares.", example: "While the VS Code ide MCP server is connected, the CLI sends the current selection and active file with every prompt, so a team adds a Read deny rule for .env and accounts for mcp__ide__* in PreToolUse allowlists.", prerequisites: ["surface-engine-config-sh", "permission-rules"], contrasts: [] },
  { id: "analytics-dashboards-ado", term: "Adoption & ROI analytics dashboards", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Hosted dashboards that surface team adoption, accept rates, and PR/line contribution so a lead can measure rollout and ROI rather than per-user cost.", example: "A lead opens claude.ai/analytics/claude-code to check the Adoption chart and uses the Leaderboard to find power users worth pairing new hires with.", prerequisites: ["auth-standardization"], contrasts: [] },
  { id: "github-contribution-attr", term: "GitHub contribution attribution", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "The rules by which Claude Code credits code to itself — a matching window around PR merges, exclusions for rewrites and generated files, and a deliberate undercount.", example: "A PR merged today credits Claude sessions from 21 days before to 2 days after, but lock files and code the developer rewrote >20% are excluded, so low numbers don't mean low usage.", prerequisites: ["managed-code-review", "analytics-dashboards-ado"], contrasts: [] },
  { id: "otel-telemetry-export", term: "OpenTelemetry cost & usage export", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Fleet-wide telemetry pushed to your own backend that the dashboards can't give you: per-user token/cost breakdowns and a SIEM audit stream.", example: "Setting CLAUDE_CODE_ENABLE_TELEMETRY=1 with an OTLP endpoint in managed settings exports claude_code.cost.usage broken down per user, model, and skill.", prerequisites: ["analytics-dashboards-ado"], contrasts: [] },
  { id: "cost-attribution-dimensi", term: "Multi-team cost attribution", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Tagging telemetry with custom resource attributes and injecting a user identity so spend can be sliced by team, department, or person on every datapoint.", example: "Setting OTEL_RESOURCE_ATTRIBUTES=department=engineering,team.id=platform lets the platform team's Claude Code spend be filtered out of an organization-wide dashboard.", prerequisites: ["otel-telemetry-export"], contrasts: [] },
  { id: "siem-audit-logging", term: "Audit logging & SIEM integration", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Opt-in OTLP log events capturing tool calls, bash commands, permission changes, and optionally prompt/tool content, sent only to your endpoint for the SIEM to alert on.", example: "Enabling OTEL_LOG_TOOL_DETAILS=1 lets the SIEM see which Bash commands and MCP tools each engineer ran, while Claude Code emits raw events and leaves anomaly detection to the SIEM.", prerequisites: ["otel-telemetry-export"], contrasts: [] },
  { id: "in-session-cost-commands", term: "In-session cost & limit governance", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Slash commands that attribute plan-limit and token consumption to skills, subagents, plugins, and MCP servers so users can self-diagnose what is driving their costs.", example: "An engineer hitting limits runs /usage and sees that parallel subagents and cache misses, not normal prompts, are consuming most of their last 24 hours.", prerequisites: ["always-on-cost-budgeting", "model-and-effort-cost-le"], contrasts: [] },
  { id: "retry-capacity-resilienc", term: "Retries, capacity & fallback resilience", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Configurable retry/timeout behavior plus per-model capacity handling and ordered fallback models that keep a team working through overload incidents.", example: "During a 529 overload a user runs /model to switch to an available model, while CI jobs set CLAUDE_CODE_RETRY_WATCHDOG=1 and a fallbackModel list to ride out capacity dips.", prerequisites: ["auth-standardization"], contrasts: [] },
  { id: "auth-precedence-failures", term: "Auth precedence & credential failures", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "The rule that environment API keys and helper scripts override interactive login, so stray or stale keys cause confusing org-disabled and 403 errors until removed.", example: "An engineer gets 'This organization has been disabled' because a previous employer's ANTHROPIC_API_KEY is loaded by direnv; /status confirms it and unsetting it lets /login take effect.", prerequisites: ["auth-precedence", "auth-standardization"], contrasts: [] },
  { id: "context-window-recovery", term: "Context-window & corrupted-turn recovery", layer: "monitoring-analytics-tro", introducedIn: "stage-10", short: "Recognizing a full or thrashing context versus a corrupted transcript and choosing the right recovery — compaction or chunking versus rewind or a fresh session.", example: "On 'Autocompact is thrashing' the fix is chunking large file reads or moving work to a subagent, whereas a tool-block mismatch needs /rewind because it persists across --resume.", prerequisites: ["compaction-survival"], contrasts: [] },
  { id: "model-pinning", term: "Model pinning", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Explicitly setting each model-tier env var to a concrete model ID/deployment so the team runs a known version instead of a drifting built-in alias default.", example: "Setting ANTHROPIC_DEFAULT_OPUS_MODEL=claude-opus-4-8 before rollout so the 'opus' alias doesn't silently resolve to whatever per-provider default lags behind, and so the team upgrades on your timing, not the vendor's.", prerequisites: ["team-config-distribution"], contrasts: [] },
  { id: "haiku-default-cost-trap", term: "Small/fast model cost trap", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "If the background/small-fast model isn't pinned to a real Haiku deployment, it silently defaults to the PRIMARY model, so cheap tasks run at primary rates.", example: "Pinning ANTHROPIC_DEFAULT_HAIKU_MODEL to a real Haiku deployment so session titles and other background tasks don't get billed at Opus/Sonnet rates.", prerequisites: ["model-pinning", "model-and-effort-cost-le"], contrasts: [] },
  { id: "provider-routing-precede", term: "Provider enable & routing precedence", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Which enterprise backend a request hits is decided by env-var flags with a fixed precedence order, so leftover flags silently route to the wrong provider.", example: "Leaving CLAUDE_CODE_USE_BEDROCK=1 set while intending Claude Platform on AWS sends requests to Bedrock instead, because Bedrock and Foundry take precedence over Platform-on-AWS unless you unset both.", prerequisites: ["team-config-distribution", "auth-precedence-failures"], contrasts: [] },
  { id: "team-config-distribution", term: "Centralized config distribution", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Pushing provider/model/auth config through the settings.json env block or enterprise managed settings rather than per-developer shell exports, treating keys as production credentials.", example: "Putting AWS_PROFILE and the workspace API key in settings.json's env block instead of each developer's .bashrc, so they don't leak to child processes and every teammate gets identical config.", prerequisites: ["settings-precedence", "managed-settings-gating"], contrasts: [] },
  { id: "provider-credential-chai", term: "Provider auth & credential refresh", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Each backend authenticates via its cloud SDK's credential chain, with settings hooks that re-run or export credentials when they expire mid-session.", example: "Configuring awsAuthRefresh to run 'aws sso login --profile my-profile' so an SSO token expiring during a session triggers a refresh option under /login instead of failing requests.", prerequisites: ["provider-routing-precede"], contrasts: [] },
  { id: "region-and-project-resol", term: "Region & project resolution order", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Region (and GCP project) are resolved through a precedence chain of env vars, profiles, and config files, so a stale value silently targets the wrong region/account.", example: "On Vertex, GOOGLE_CLOUD_PROJECT overrides ANTHROPIC_VERTEX_PROJECT_ID, so a leftover GOOGLE_CLOUD_PROJECT points the whole team at the wrong GCP project even though the 'official' project-id var is set.", prerequisites: ["provider-routing-precede"], contrasts: [] },
  { id: "model-access-provisionin", term: "Model access provisioning", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "Beyond auth, each provider requires explicitly enabling/approving the models or deployments (IAM/RBAC, model-access requests, portal deployments) before they can be invoked.", example: "On Vertex, Model Garden access must be requested and approved (24-48h) before any model invokes; on Foundry you must create Opus/Sonnet/Haiku deployments in the portal and match the alias env vars to those deployment names.", prerequisites: ["provider-credential-chai"], contrasts: [] },
  { id: "llm-gateway", term: "LLM gateway (LiteLLM)", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "A proxy in front of one or more backends that exposes a supported API format and centralizes load balancing, fallbacks, auth, and cost tracking for the whole team.", example: "Pointing ANTHROPIC_BASE_URL at a LiteLLM server's unified Anthropic endpoint so all teammates get load balancing and fallbacks, with per-user keys minted by an apiKeyHelper script (which a stray ANTHROPIC_AUTH_TOKEN would override).", prerequisites: ["provider-routing-precede", "retry-capacity-resilienc"], contrasts: [] },
  { id: "gateway-forwarding-contr", term: "Gateway header/attribution contract", layer: "enterprise-providers-gat", introducedIn: "stage-11", short: "A gateway must forward Anthropic beta/version headers and pass through Claude Code's session/agent ID headers, or functionality silently degrades and cost attribution breaks.", example: "Configuring the gateway to preserve anthropic-beta/anthropic-version and to read X-Claude-Code-Session-Id / X-Claude-Code-Agent-Id so per-session and per-subagent spend can be attributed without parsing request bodies.", prerequisites: ["llm-gateway"], contrasts: [] },
];

